export default function unique(arr) {
  const seen = new Set();
  const result = [];
  for (const item of arr) {
    if (!seen.has(item)) {
      seen.add(item);
      result.push(item);
    }
  }
  return result;
}

approach2.code:
export default function unique(arr) {
  return [...new Set(arr)];
}

